evaluators.evaluation_logic:
const checkpoints = [];

let quotes = [];
try {
  quotes = JSON.parse(localStorage.getItem('request_quotes') || '[]');
} catch (e) {
  quotes = [];
}

// Quotes that match machining type, stainless material family, dimensions, quantity, and tolerance <= 0.02 mm
const dimsAndTolQuotes = quotes.filter(q => {
  if (!q || q.machining_type !== 'cnc_turning') return false;
  if (typeof q.material !== 'string' || !q.material.startsWith('stainless_steel')) return false;
  if (typeof q.length_mm !== 'number' || q.length_mm !== 120) return false;
  if (typeof q.diameter_mm !== 'number' || q.diameter_mm !== 20) return false;
  if (q.quantity !== 250) return false;
  if (typeof q.tolerance_value_mm !== 'number') return false;
  if (!(q.tolerance_value_mm > 0 && q.tolerance_value_mm <= 0.02)) return false;
  return true;
});

// Subset that also matches standard lead time <= 15 business days
const fullMatchingQuotes = dimsAndTolQuotes.filter(q => {
  if (q.lead_time_type !== 'standard') return false;
  if (typeof q.lead_time_business_days !== 'number') return false;
  if (!(q.lead_time_business_days > 0 && q.lead_time_business_days <= 15)) return false;
  return true;
});

// CP1 (0.6): At least one RFQ matches CNC turning, stainless, correct dimensions/quantity, and tolerance <= 0.02 mm
checkpoints.push({ passed: dimsAndTolQuotes.length > 0, weight: 0.6 });

// CP2 (0.4): Among those, at least one also uses STANDARD lead time <= 15 business days
checkpoints.push({ passed: fullMatchingQuotes.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let services = [], specs = [], inquiries = [];
try {
  services = JSON.parse(localStorage.getItem('services') || '[]');
} catch (e) { services = []; }
try {
  specs = JSON.parse(localStorage.getItem('service_material_specs') || '[]');
} catch (e) { specs = []; }
try {
  inquiries = JSON.parse(localStorage.getItem('service_inquiries') || '[]');
} catch (e) { inquiries = []; }

const serviceById = {};
services.forEach(s => { if (s && s.id) serviceById[s.id] = s; });

const aluminumMaterials = ['aluminum_6061', 'aluminum_7075'];
const aluminumSpecsByService = {};

specs.forEach(spec => {
  if (!spec || !spec.service_id) return;
  if (!aluminumMaterials.includes(spec.material)) return;
  if (typeof spec.min_tolerance_in !== 'number') return;
  if (!aluminumSpecsByService[spec.service_id]) aluminumSpecsByService[spec.service_id] = [];
  aluminumSpecsByService[spec.service_id].push(spec);
});

// 5-axis services that support aluminum with min_tolerance_in <= 0.005 in
const candidateServices = [];
services.forEach(svc => {
  if (!svc || svc.process_type !== 'five_axis_cnc_machining') return;
  const svcSpecs = aluminumSpecsByService[svc.id] || [];
  const hasReqTol = svcSpecs.some(sp => sp.min_tolerance_in <= 0.005);
  if (!hasReqTol) return;
  const bestTol = svcSpecs.reduce((best, sp) => (best === null || sp.min_tolerance_in < best ? sp.min_tolerance_in : best), null);
  svc.__bestAlTolIn = bestTol;
  candidateServices.push(svc);
});

let tightestServiceIds = [];
if (candidateServices.length > 0) {
  const tightestTol = candidateServices.reduce((best, svc) => (best === null || (typeof svc.__bestAlTolIn === 'number' && svc.__bestAlTolIn < best) ? svc.__bestAlTolIn : best), null);
  tightestServiceIds = candidateServices
    .filter(svc => typeof svc.__bestAlTolIn === 'number' && svc.__bestAlTolIn === tightestTol)
    .map(svc => svc.id);
}

const isSampleProjectInquiry = (inq) => {
  const text = ((inq.subject || '') + ' ' + (inq.message || '')).toLowerCase();
  return text.includes('sample') && text.includes('project');
};

// Inquiries to any 5-axis aluminum service meeting the tolerance and requesting a sample project
const qualifyingInquiriesAny = inquiries.filter(inq => {
  if (!inq || !inq.service_id) return false;
  const svc = serviceById[inq.service_id];
  if (!svc || svc.process_type !== 'five_axis_cnc_machining') return false;
  const svcSpecs = aluminumSpecsByService[svc.id] || [];
  const hasReqTol = svcSpecs.some(sp => sp.min_tolerance_in <= 0.005);
  if (!hasReqTol) return false;
  if (!isSampleProjectInquiry(inq)) return false;
  return true;
});

// Subset where the service is one of the tightest-tolerance aluminum services
const qualifyingInquiriesTightest = qualifyingInquiriesAny.filter(inq => tightestServiceIds.includes(inq.service_id));

// CP1 (0.4): Submitted an inquiry requesting a sample project to a 5-axis aluminum service with aluminum tolerance <= 0.005 in
checkpoints.push({ passed: qualifyingInquiriesAny.length > 0, weight: 0.4 });

// CP2 (0.6): That inquiry targets a service with the tightest available aluminum tolerance among all such services
checkpoints.push({ passed: qualifyingInquiriesTightest.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let estimates = [];
try {
  estimates = JSON.parse(localStorage.getItem('cost_estimates') || '[]');
} catch (e) { estimates = []; }

const isFineFinish = (sf) => sf === 'ra_1_6_um_fine' || sf === 'ra_0_8_um_fine' || sf === 'ra_0_4_um_superfine';

const medEstimates = estimates.filter(est => {
  if (!est) return false;
  if (est.part_type !== 'medical_implant_component') return false;
  if (est.quantity !== 100) return false;
  if (!isFineFinish(est.surface_finish)) return false;
  if (typeof est.estimated_cost_per_unit !== 'number') return false;
  return true;
});

const titaniumEstimates = medEstimates.filter(est => typeof est.material === 'string' && est.material.indexOf('titanium_') === 0);
const stainlessEstimates = medEstimates.filter(est => typeof est.material === 'string' && est.material.indexOf('stainless_steel_') === 0);

const getCheapest = (arr) => arr.reduce((best, est) => (!best || est.estimated_cost_per_unit < best.estimated_cost_per_unit ? est : best), null);

const cheapestTi = getCheapest(titaniumEstimates);
const cheapestSS = getCheapest(stainlessEstimates);

const preferred = estimates.find(est => est && est.is_preferred);

// CP1 (0.3): Created at least one titanium and one stainless estimate for a medical part, qty 100, fine finish
checkpoints.push({ passed: !!cheapestTi && !!cheapestSS, weight: 0.3 });

// CP2 (0.3): Marked as preferred an estimate that is for that medical, qty 100, fine-finish titanium or stainless scenario
const cp2Passed = !!preferred &&
  preferred.part_type === 'medical_implant_component' &&
  preferred.quantity === 100 &&
  isFineFinish(preferred.surface_finish) &&
  ( (typeof preferred.material === 'string' && preferred.material.indexOf('titanium_') === 0) ||
    (typeof preferred.material === 'string' && preferred.material.indexOf('stainless_steel_') === 0) );
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.4): Preferred estimate is the cheaper of the titanium vs stainless options and has unit cost < $40
let correctPreferred = null;
if (cheapestTi && cheapestSS) {
  const cheaper = cheapestTi.estimated_cost_per_unit < cheapestSS.estimated_cost_per_unit ? cheapestTi : cheapestSS;
  if (cheaper.estimated_cost_per_unit < 40) {
    correctPreferred = cheaper;
  }
}
const cp3Passed = !!correctPreferred && !!preferred && preferred.id === correctPreferred.id;
checkpoints.push({ passed: cp3Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let requests = [], caseStudies = [];
try {
  requests = JSON.parse(localStorage.getItem('similar_project_requests') || '[]');
} catch (e) { requests = []; }
try {
  caseStudies = JSON.parse(localStorage.getItem('case_studies') || '[]');
} catch (e) { caseStudies = []; }

const csById = {};
caseStudies.forEach(cs => { if (cs && cs.id) csById[cs.id] = cs; });

// Requests tied to aerospace case studies with delivery <= 10 days and target_delivery_days <= 10
const qualifyingBase = requests.filter(req => {
  if (!req || !req.case_study_id) return false;
  const cs = csById[req.case_study_id];
  if (!cs) return false;
  if (cs.industry !== 'aerospace') return false;
  if (typeof cs.delivery_time_days !== 'number' || cs.delivery_time_days > 10) return false;
  if (typeof req.target_delivery_days !== 'number' || req.target_delivery_days > 10) return false;
  return true;
});

// Among those, ensure the project name references the case study title (CTA usage)
const qualifyingWithReference = qualifyingBase.filter(req => {
  const cs = csById[req.case_study_id];
  if (!cs) return false;
  const projectName = (req.project_name || '').toLowerCase();
  const title = (cs.title || '').toLowerCase();
  return !!title && projectName.includes(title);
});

// CP1 (0.5): Submitted a similar project request for an aerospace case study with delivery <= 10 days and target delivery <= 10 days
checkpoints.push({ passed: qualifyingBase.length > 0, weight: 0.5 });

// CP2 (0.5): That request's project name explicitly references the originating case study (e.g., default CTA name)
checkpoints.push({ passed: qualifyingWithReference.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let comparisons = [], machines = [];
try {
  comparisons = JSON.parse(localStorage.getItem('equipment_comparisons') || '[]');
} catch (e) { comparisons = []; }
try {
  machines = JSON.parse(localStorage.getItem('machines') || '[]');
} catch (e) { machines = []; }

const activeComparison = comparisons.find(c => c && c.email_sent === false) || null;
const selectedMachineIds = activeComparison && Array.isArray(activeComparison.machine_ids)
  ? activeComparison.machine_ids.slice()
  : [];

const machineById = {};
machines.forEach(m => { if (m && m.id) machineById[m.id] = m; });

const selectedMachines = selectedMachineIds.map(id => machineById[id]).filter(Boolean);

const qualifyingSelectedMachines = selectedMachines.filter(m => {
  if (!m) return false;
  if (typeof m.max_part_length_mm !== 'number' || m.max_part_length_mm < 500) return false;
  if (typeof m.min_surface_roughness_ra_um !== 'number' || m.min_surface_roughness_ra_um > 1.6) return false;
  return true;
});

// All qualifying machines in the shop, filtered and sorted by newest commission_date first
const qualifyingAll = machines.filter(m => {
  if (!m || !m.is_active) return false;
  if (typeof m.max_part_length_mm !== 'number' || m.max_part_length_mm < 500) return false;
  if (typeof m.min_surface_roughness_ra_um !== 'number' || m.min_surface_roughness_ra_um > 1.6) return false;
  return true;
}).slice();

qualifyingAll.sort((a, b) => {
  const da = new Date(a.commission_date || a.createdAt || 0).getTime();
  const db = new Date(b.commission_date || b.createdAt || 0).getTime();
  return db - da;
});

const firstThreeIds = qualifyingAll.slice(0, 3).map(m => m.id);

// CP1 (0.5): Active comparison has exactly three machines and all three meet length >= 500 mm and Ra <= 1.6 µm
const cp1Passed = (selectedMachines.length === 3 && qualifyingSelectedMachines.length === 3);
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): Those three machines are exactly the first three qualifying machines by newest commission date (newest_first)
let cp2Passed = false;
if (firstThreeIds.length === 3 && selectedMachineIds.length === 3) {
  cp2Passed = firstThreeIds.every((id, idx) => selectedMachineIds[idx] === id);
}
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let tours = [], metadata = null;
try {
  tours = JSON.parse(localStorage.getItem('plant_tour_requests') || '[]');
} catch (e) { tours = []; }
try {
  metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
} catch (e) { metadata = null; }

let baselineDate;
if (metadata && metadata.baselineDate) {
  baselineDate = new Date(metadata.baselineDate);
  if (isNaN(baselineDate.getTime())) baselineDate = new Date();
} else {
  baselineDate = new Date();
}

const year = baselineDate.getFullYear();
const month = baselineDate.getMonth();
const nextMonth = (month + 1) % 12;
const nextYear = month === 11 ? year + 1 : year;

const isWeekday = (d) => {
  const day = d.getDay();
  return day >= 1 && day <= 5; // Mon-Fri
};

const qualifyingTours = tours.filter(req => {
  if (!req) return false;
  if (req.time_slot !== 'morning') return false;
  if (req.attendees_count !== 3) return false;
  if (!req.visit_date) return false;
  const d = new Date(req.visit_date);
  if (isNaN(d.getTime())) return false;
  if (d.getFullYear() !== nextYear || d.getMonth() !== nextMonth) return false;
  if (!isWeekday(d)) return false;
  return true;
});

// Single CP (1.0): At least one plant tour request meets attendees=3, morning slot, weekday, and date in next calendar month
checkpoints.push({ passed: qualifyingTours.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let carts = [], cartItems = [], products = [];
try {
  carts = JSON.parse(localStorage.getItem('carts') || '[]');
} catch (e) { carts = []; }
try {
  cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
} catch (e) { cartItems = []; }
try {
  products = JSON.parse(localStorage.getItem('products') || '[]');
} catch (e) { products = []; }

const openCart = carts.find(c => c && c.status === 'open') || null;
const cartId = openCart ? openCart.id : null;

const itemsForCart = cartItems.filter(ci => ci && cartId && ci.cart_id === cartId);

const productById = {};
products.forEach(p => { if (p && p.id) productById[p.id] = p; });

const itemsWithProducts = itemsForCart.map(ci => ({ ci, product: productById[ci.product_id] || null })).filter(obj => !!obj.product);

const validPriceQtyItems = itemsWithProducts.filter(obj => {
  const ci = obj.ci, p = obj.product;
  if (ci.quantity !== 1) return false;
  if (typeof p.price !== 'number' || p.price >= 150) return false;
  return true;
});

const turningItems = validPriceQtyItems.filter(obj => obj.product.category === 'cnc_turning_parts');
const millingItems = validPriceQtyItems.filter(obj => obj.product.category === 'cnc_milling_parts');

// CP1 (0.5): Open cart has exactly 3 line items, all with quantity 1 and price < $150
const cp1Passed = (itemsForCart.length === 3 && validPriceQtyItems.length === 3);
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): Among those 3 items, exactly 2 are turning parts and 1 is a milling part
const cp2Passed = (turningItems.length === 2 && millingItems.length === 1);
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let calcs = [], options = [];
try {
  calcs = JSON.parse(localStorage.getItem('lead_time_calculations') || '[]');
} catch (e) { calcs = []; }
try {
  options = JSON.parse(localStorage.getItem('lead_time_options') || '[]');
} catch (e) { options = []; }

const candidateCalcs = calcs.filter(calc => {
  if (!calc) return false;
  if (calc.quantity !== 500) return false;
  if (!Array.isArray(calc.processes)) return false;
  const procs = calc.processes;
  if (!procs.includes('anodizing')) return false;
  if (!procs.includes('dimensional_inspection')) return false;
  return true;
});

let cp1Passed = false;
let cp2Passed = false;

candidateCalcs.forEach(calc => {
  const opts = options.filter(o => o && o.calculation_id === calc.id);
  if (!opts.length) return;

  const selected = opts.find(o => o.is_selected);
  if (!selected) return;

  const qualifyingOpts = opts.filter(o => typeof o.total_lead_time_days === 'number' && o.total_lead_time_days <= 12);
  if (!qualifyingOpts.length) return;

  const selectedIsFastEnough = qualifyingOpts.some(o => o.id === selected.id);
  if (selectedIsFastEnough) {
    cp1Passed = true;
  }

  const cheapestQualifying = qualifyingOpts.reduce((best, o) => (!best || o.estimated_shipping_cost < best.estimated_shipping_cost ? o : best), null);
  if (selectedIsFastEnough && cheapestQualifying && selected.id === cheapestQualifying.id) {
    cp2Passed = true;
  }
});

// CP1 (0.4): For some calc with qty 500 and processes including anodizing & dimensional inspection, user selected an option with total lead time <= 12 days
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.6): For such a calc, the selected option is the cheapest among all options with total lead time <= 12 days
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
